/** * Data-layer implementacija WorkoutStatsRepository. * * Bere podatke iz Firestore (prek FirestoreHelper) in lokalne SharedPrefs (fallback). * Wrappira UserProfileManager.getWorkoutStats() logiko v domenski interface. * * todayIsRest je vedno false — ViewModel izračuna isRestDay iz plan modela * (ki je presentation concern, ne domenski concern). * * @param prefs UserPreferencesRepository za lokalni fallback (SharedPrefs) */ class UserWorkoutStatsRepository( private val prefs: UserPreferencesRepository ) : WorkoutStatsRepository {
override suspend fun getWorkoutStats(email: String): WorkoutStats? { return try { val docRef = FirestoreHelper.getCurrentUserDocRef() ?: return null val doc = docRef.get().await() if (!doc.exists()) return null
val todayStr = Clock.System.now() .toLocalDateTime(TimeZone.Companion.currentSystemDefault()).date.toString()
@Suppress("UNCHECKED_CAST") val dailyHistory = (doc.get("dailyHistory") as? Map<String, Any>) ?: emptyMap() val todayStatus = dailyHistory[todayStr]?.toString() ?: ""
WorkoutStats( streakDays = doc.getLong("streak_days")?.toInt() ?: 0, streakFreezes = doc.getLong("streak_freezes")?.toInt() ?: 0, weeklyDone = doc.getLong("weekly_done")?.toInt() ?: 0, weeklyTarget = doc.getLong("weekly_target")?.toInt() ?: 3, planDay = doc.getLong("plan_day")?.toInt() ?: 1, totalWorkoutsCompleted = doc.getLong("total_workouts_completed")?.toInt() ?: 0, lastWorkoutEpoch = doc.getLong("last_workout_epoch") ?: 0L, todayStatus = todayStatus, todayIsRest = false, // ViewModel izračuna iz plan modela dailyKcal = prefs.getDailyCalories().toInt() ) } catch (e: Exception) { null } }
override suspend fun isWorkoutDoneToday(): Boolean = prefs.isWorkoutDoneToday()
override suspend fun getPlanDay(): Int = prefs.getPlanDay()
override suspend fun getDailyCalories(): Int = prefs.getDailyCalories().toInt() }

package com.example.myapplication.data.repository
import com.example.myapplication.data.settings.UserPreferencesRepository import com.example.myapplication.domain.model.UserDayStatus import com.example.myapplication.domain.repository.WorkoutStats import com.example.myapplication.domain.repository.WorkoutStatsRepository import com.example.myapplication.data.store.FirestoreHelper import kotlinx.coroutines.tasks.await import kotlinx.datetime.Clock import kotlinx.datetime.DateTimeUnit import kotlinx.datetime.LocalDate import kotlinx.datetime.TimeZone import kotlinx.datetime.minus import kotlinx.datetime.toLocalDateTime
/** * Data-layer implementacija WorkoutStatsRepository. * * Bere podatke iz Firestore (prek FirestoreHelper) in lokalne SharedPrefs (fallback). * Wrappira UserProfileManager.getWorkoutStats() logiko v domenski interface. * * todayIsRest je vedno false — ViewModel izračuna isRestDay iz plan modela * (ki je presentation concern, ne domenski concern). * * @param prefs UserPreferencesRepository za lokalni fallback (SharedPrefs) */ class UserWorkoutStatsRepository( private val prefs: UserPreferencesRepository ) : WorkoutStatsRepository {
override suspend fun getWorkoutStats(email: String): WorkoutStats? { return try { val docRef = FirestoreHelper.getCurrentUserDocRef() ?: return null val doc = docRef.get().await() if (!doc.exists()) return null
val today = Clock.System.now() .toLocalDateTime(TimeZone.currentSystemDefault()).date val todayStr = today.toString()
@Suppress("UNCHECKED_CAST") val dailyHistory = (doc.get("dailyHistory") as? Map<String, Any>) ?: emptyMap() // Faza 21: pretvori surovi Firestore string v tipsko-varni UserDayStatus val todayStatus = UserDayStatus.fromFirestore(dailyHistory[todayStr]?.toString())
// ✅ FIX: weeklyDone se izračuna dinamično iz dailyHistory tekočega tedna (pon–danes). // S tem se števec samodejno ponastavi ob novem tednu — ni potrebe po ločenem reset polju. val daysFromMonday = today.dayOfWeek.value - 1 // Monday.value=1, Sunday.value=7 → pon=0 val monday = today.minus(daysFromMonday, DateTimeUnit.DAY) val weeklyDoneCalc = dailyHistory.entries.count { (dateStr, status) -> val s = status.toString() if (s != "WORKOUT_DONE" && s != "REST_WORKOUT_DONE") return@count false try { val d = LocalDate.parse(dateStr); d in monday..today } catch (_: Exception) { false } }
WorkoutStats( streakDays = doc.getLong("streak_days")?.toInt() ?: 0, streakFreezes = doc.getLong("streak_freezes")?.toInt() ?: 0, weeklyDone = weeklyDoneCalc, weeklyTarget = doc.getLong("weekly_target")?.toInt() ?: 3, planDay = doc.getLong("plan_day")?.toInt() ?: 1, totalWorkoutsCompleted = doc.getLong("total_workouts_completed")?.toInt() ?: 0, lastWorkoutEpoch = doc.getLong("last_workout_epoch") ?: 0L, todayStatus = todayStatus, todayIsRest = false, // ViewModel izračuna iz plan modela dailyKcal = prefs.getDailyCalories().toInt() ) } catch (e: Exception) { null } }
override suspend fun isWorkoutDoneToday(): Boolean = prefs.isWorkoutDoneToday()
override suspend fun getPlanDay(): Int = prefs.getPlanDay()
override suspend fun getDailyCalories(): Int = prefs.getDailyCalories().toInt() }

package com.example.myapplication.domain.gamification
/** * Ključni repozitorij za gamification. * * Ta interface se nahaja v DOMAIN sloju (brez Android odvisnosti). * Definira contract "kaj se da narediti glede streaka ali XP-jev" * in zagotavlja SAMO EN Vir Resnice. */ interface GamificationRepository {
/** * Shrani XP (s Firebase batch logiko). * @param amount Količina XP (npr. 10). * @param reason Razlog prejema ("Workout complete", "Daily Login"). */ suspend fun awardXP(amount: Int, reason: String)
/** * Vrni trenutno število streaka iz enotnega vira podatkov. */ suspend fun getCurrentStreak(): Int
/** * Povečaj ali ohrani streak. Zažene se, ko je uspešno zabeleženo, * in pod kapuco reši tisti "Heisenbug". * @param isWorkoutSuccess Je bil trening ali rest day uspešno obkljukan danes? * @param activityType Tip aktivnosti za dailyHistory mapo: "WORKOUT_DONE" ali "STRETCHING_DONE" * @return Novi streak po posodobitvi (0 ob napaki) */ suspend fun updateStreak(isWorkoutSuccess: Boolean, activityType: String = "WORKOUT_DONE"): Int
/** * Označi TODAY kot "PENDING_STRETCHING" v dailyHistory mapi. * Kliče se, ko app ugotovi da je danes rest day — a uporabnik * še NI opravil raztezanja. Status ne pripiše streak +1. * Prehod v "STRETCHING_DONE" se zgodi SAMO prek [updateStreak] ob * eksplicitni uporabnikovi akciji. * * ⛔ runMidnightCheck() NE sme klicati te metode — polnočni check * preverja VČERAJ (ne danes) in ne sme avtokonkludirati rest dnevov. */ suspend fun markRestDayPending()
/** * Ozadičen worker (polnoč) reče repositoryju: "Preveri in resetiraj, če manjkajo workouti". * ⚠️ Ta metoda analizira SAMO VČERAJŠNJI dan — nikoli ne auto-complete todayja. */ suspend fun runMidnightStreakCheck()
/** * Za uporabo Streak Freeze, če je na voljo. */ suspend fun consumeStreakFreeze(): Boolean
/** * Faza 12b — Unified Activity Completion Engine (nadomešča processWorkoutCompletion). * * ENA atomarna Firestore transakcija za VSAKO aktivnost — redni trening ALI extra rest-day workout: * - Epoch-based streak izračun z isRestDay matriko (dayDiff z Streak Freeze podporo) * - Vedno zapiše dailyHistory.$today ("WORKOUT_DONE" ali "REST_WORKOUT_DONE") * - Vedno posodobi last_activity_epoch → midnight check nikoli ne vidi praznega dne * - Atomarno dodeli XP in beleži xp_history * - Zapiše porabljene kalorije v dailyLogs * * Streak matrika: * oldLastEpoch == 0L → 1 (prvi zapis) * dayDiff == 0L → oldStreak (de-dup) * dayDiff == 1L → if (isRestDay) oldStreak else oldStreak + 1 * dayDiff > 1L → freeze? ohrani : 1 * * @param isRestDay true = extra workout na rest dnevu (streak se NE poveča, a se zapiše) * @param incrementPlanDay true za redne workouty (plan_day +1), false za extra * @param xpToBeAwarded skupni XP za to aktivnost * @param xpReason razlog za XP log * @param caloriesBurned porabljene kalorije za Nutrition bridge (0.0 = preskoči) */ suspend fun processActivityCompletion( isRestDay: Boolean, incrementPlanDay: Boolean, xpToBeAwarded: Int, xpReason: String, caloriesBurned: Double )
/** * Vrni status današnjega dne iz dailyHistory mape. * Možne vrednosti: "WORKOUT_DONE", "STRETCHING_DONE", "PENDING_STRETCHING", * "FROZEN", "MISSED", ali null (dan ni bil zabeležen). */ suspend fun getTodayStatus(): String?
/** * Zapiši porabljene kalorije v dnevni log (dailyLogs/{todayStr}). * Nadomešča direktno klicanje DailyLogRepository iz domain layer-a. * * @param todayStr Datum v formatu "YYYY-MM-DD" * @param calories Porabljene kalorije (dodane k obstoječim) */ suspend fun logBurnedCalories(todayStr: String, calories: Double)
/** * Vrni trenutno gamification stanje (weeklyTarget, workoutDoneToday). * Nadomešča workoutDoneProvider/weeklyTargetProvider lambde v ManageGamificationUseCase. * KMP-ready: suspending namesto Flow-based lambda injection. */ suspend fun getGamificationState(): com.example.myapplication.domain.gamification.GamificationState }

package com.example.myapplication.domain.gamification

import com.example.myapplication.domain.model.UserDayStatus

/**
 * SSOT za gamification logiko.
 *
 * Faza 21: processActivityCompletion() in updateStreak() so zamenjani z
 * moveToNextDay() — eno atomarno Firestore transakcijo za VSE poti.
 *
 * KMP-ready interface brez Android odvisnosti.
 */
interface GamificationRepository {

    /**
     * Shrani XP (s Firebase batch logiko).
     * @param amount Količina XP (npr. 10).
     * @param reason Razlog prejema ("Workout complete", "Daily Login").
     */
    suspend fun awardXP(amount: Int, reason: String)

    /**
     * Vrni trenutno število streaka iz enotnega vira podatkov.
     */
    suspend fun getCurrentStreak(): Int

    /**
     * Označi TODAY kot [UserDayStatus.REST_DAY_PENDING] v dailyHistory mapi.
     * Kliče se, ko app ugotovi da je danes rest day — a uporabnik
     * še NI opravil raztezanja. Status ne pripiše streak +1.
     *
     * ⛔ runMidnightCheck() NE sme klicati te metode.
     */
    suspend fun markRestDayPending()

    /**
     * Ozadičen worker (polnoč) reče repositoryju: "Preveri in resetiraj, če manjkajo workouti".
     * ⚠️ Ta metoda analizira SAMO VČERAJŠNJI dan — nikoli ne auto-complete todayja.
     */
    suspend fun runMidnightStreakCheck()

    /**
     * Porabi Streak Freeze, če je na voljo.
     */
    suspend fun consumeStreakFreeze(): Boolean

    /**
     * Vrni tipsko-varni [UserDayStatus] za danes iz dailyHistory mape.
     * Vrne [UserDayStatus.WORKOUT_PENDING] če dan ni bil zabeležen.
     */
    suspend fun getTodayStatus(): UserDayStatus

    /**
     * Zapiši porabljene kalorije v dnevni log (dailyLogs/{todayStr}).
     * Uporablja se za ručno beleženje (RunTracker, ManualExercise) izven moveToNextDay().
     */
    suspend fun logBurnedCalories(todayStr: String, calories: Double)

    /**
     * Vrni trenutno gamification stanje (weeklyTarget, workoutDoneToday).
     */
    suspend fun getGamificationState(): GamificationState

    // ─────────────────────────────────────────────────────────────────────────
    // moveToNextDay — SSOT za VSE aktivnostne zaključke (Faza 21)
    //
    // Nadomešča oba stara klica:
    //   • processActivityCompletion(isRestDay, incrementPlanDay, xp, reason, cals)
    //   • updateStreak(isWorkoutSuccess, activityType)
    //
    // ENA atomarna Firestore transakcija za:
    //   ① Preveritev in de-duplikacija (ne prepiše višje prioritete)
    //   ② Streak izračun (epoch-based, Freeze podpora)
    //   ③ Posodobitev plan_day (samo za WORKOUT_DONE z incrementPlanDay=true)
    //   ④ XP + Level posodobitev
    //   ⑤ Zapis v dailyHistory z UserDayStatus.firestoreValue
    //   ⑥ Porabljene kalorije v dailyLogs (Nutrition bridge)
    //
    // Logika glede na [newStatus]:
    //   WORKOUT_DONE     → streak+1, plan_day+1 (če incrementPlanDay=true)
    //   REST_WORKOUT_DONE → streak ohranjen, plan_day nespremenjen
    //   REST_DAY_DONE    → streak+1, plan_day nespremenjen
    //
    // @return Novi streak po transakciji (0 ob napaki ali de-dup preskoček).
    // ─────────────────────────────────────────────────────────────────────────
    suspend fun moveToNextDay(
        newStatus: UserDayStatus,
        xpToBeAwarded: Int = 0,
        xpReason: String = "",
        caloriesBurned: Double = 0.0,
        /** true = plan_day +1. Privzeto: samo za WORKOUT_DONE. */
        incrementPlanDay: Boolean = newStatus.shouldIncrementPlanDay
    ): Int
}

package com.example.myapplication.domain.gamification

import com.example.myapplication.domain.model.AchievementProfile
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.flow

/**
 * Rezultat zaključenega workout-a.
 * unlockedBadges: seznam badge ID-jev (ne Badge objektov — brez data layer odvisnosti).
 */
data class WorkoutCompletionResult(
    val unlockedBadges: List<String> = emptyList(),
    val xpAwarded: Int,
    val isCritical: Boolean
)

data class GamificationState(
    val weeklyTarget: Int = 0,
    val workoutDoneToday: Boolean = false
)

/**
 * UseCase za gamification logiko.
 *
 * Clean Architecture: komunicira SAMO z GamificationRepository (domain interface).
 * KMP-ready: brez Android, data.settings, data.UserProfile odvisnosti.
 *
 * Faza 12: recordWorkoutCompletion() izračuna XP pred klicem atomarnega
 * processWorkoutCompletion(). completeWorkoutSession() IZBRISAN (legacy stub).
 */
class ManageGamificationUseCase(
    private val repository: GamificationRepository
) {

    fun getGamificationStateFlow(): Flow<GamificationState> = flow {
        try { emit(repository.getGamificationState()) }
        catch (_: Exception) { emit(GamificationState()) }
    }

    // ─────────────────────────────────────────────────────────────────────────
    // recordWorkoutCompletion — Faza 12b: XP izračun + VEDNO en atomaren klic
    //
    // KRITIČNA FIX: isRestDay NE zaobide klica repozitorija!
    // Brez vpisa v dailyHistory in last_activity_epoch midnight worker vidi prazen dan
    // → porabi Streak Freeze ali resetira streak na 0, čeprav je uporabnik treniral.
    //
    // processActivityCompletion pokrije VSE scenarije v ENI transakciji:
    //   isRestDay=false → "WORKOUT_DONE" + streak+1
    //   isRestDay=true  → "REST_WORKOUT_DONE" + streak ohranjen (ne pade!)
    // ─────────────────────────────────────────────────────────────────────────
    /**
     * Zaključi vadbo: izračuna skupni XP, nato pokliče atomarni engine za vse scenarije.
     *
     * XP formula:
     *   calorieXP  = caloriesBurned / 8   (1 XP na 8 kcal)
     *   baseXP     = 50
     *   Critical   = 10% verjetnost → baseXP × 2
     *   totalXP    = finalBaseXP + calorieXP
     *
     * @param caloriesBurned kcal porabljene med vadbo
     * @param hour           ura vadbe (rezervirano za Early Bird / Night Owl bonus)
     * @param isRestDay      true = extra vadba na rest dnevu → streak se ohrani (ne poveča, ne pade)
     * @param incrementPlanDay true = redni workout → plan_day +1 v Firestore
     */
    suspend fun recordWorkoutCompletion(
        caloriesBurned: Double,
        hour: Int,
        isRestDay: Boolean = false,
        incrementPlanDay: Boolean = true
    ): WorkoutCompletionResult {

        // ── XP izračun (pred klicem repozitorija) ────────────────────────────
        val calorieXP   = (caloriesBurned / 8).toInt()         // 1 XP = 8 kcal
        val baseXP      = 50
        val isCritical  = kotlin.random.Random.nextFloat() < 0.1f
        val finalBaseXP = if (isCritical) baseXP * 2 else baseXP
        val totalXP     = finalBaseXP + calorieXP
        // ─────────────────────────────────────────────────────────────────────

        // VEDNO pokliči atomarni engine — isRestDay=true NE sme zaobiti tega klica!
        repository.processActivityCompletion(
            isRestDay        = isRestDay,
            incrementPlanDay = incrementPlanDay,
            xpToBeAwarded    = totalXP,
            xpReason         = if (isRestDay) "REST_WORKOUT_COMPLETE" else "WORKOUT_COMPLETE",
            caloriesBurned   = caloriesBurned
        )

        return WorkoutCompletionResult(emptyList(), totalXP, isCritical)
    }

    suspend fun awardXP(amount: Int, reason: String) = repository.awardXP(amount, reason)

    suspend fun recordPlanCreation() = repository.awardXP(100, "PLAN_CREATED")

    suspend fun recordLoginOnly() = repository.awardXP(10, "DAILY_LOGIN")

    /**
     * Vrni badge napredek za danega uporabnika.
     * @param profile AchievementProfile domenski model (ViewModel ga konvertira iz data.UserProfile)
     */
    fun getBadgeProgress(badgeId: String, profile: AchievementProfile): Int {
        return when (badgeId) {
            "first_workout", "committed_10", "committed_50",
            "committed_100", "committed_250", "committed_500" ->
                profile.totalWorkoutsCompleted
            "calorie_crusher_1k", "calorie_crusher_5k", "calorie_crusher_10k" ->
                profile.totalCaloriesBurned.toInt()
            "level_5", "level_10", "level_25", "level_50" ->
                profile.level
            "first_follower", "social_butterfly", "influencer", "celebrity" ->
                profile.followers
            "early_bird"  -> profile.earlyBirdWorkouts
            "night_owl"   -> profile.nightOwlWorkouts
            "week_warrior", "month_master", "year_champion" ->
                profile.currentLoginStreak
            "first_plan", "plan_master" ->
                profile.totalPlansCreated
            else -> 0
        }
    }

    suspend fun checkAndSyncBadgesOnStartup(): List<String> = emptyList()

    /**
     * Faza 4b: Uporabnik je opravil raztezanje na rest dnevu.
     *
     * FIX #3 — Koledarski zaklep:
     * Preverimo DEJANSKI DATUM in status iz repozitorija. Če je na isti
     * kalendarski dan dailyHistory že vseboval "WORKOUT_DONE" ali
     * "REST_WORKOUT_DONE", raztezanje NI dovoljeno — vrnemo obstoječi streak
     * brez spremembe in brez zapisa.
     *
     * @return Novi streak (ali obstoječi streak če akcija ni dovoljena)
     */
    suspend fun restDayInitiated(): Int {
        // FIX: server-side guard — preveri aktualni datum v bazi
        val todayStatus = runCatching { repository.getTodayStatus() }.getOrNull()
        if (todayStatus == "WORKOUT_DONE" || todayStatus == "REST_WORKOUT_DONE") {
            // Redni trening je bil danes že opravljen — raztezanje ni dovoljeno na isti dan.
            // Vrni obstoječi streak brez spremembe.
            return runCatching { repository.getCurrentStreak() }.getOrDefault(0)
        }

        val newStreak = repository.updateStreak(
            isWorkoutSuccess = true,
            activityType = "STRETCHING_DONE"
        )
        repository.awardXP(10, "REST_DAY")
        return newStreak
    }

    /** Worker (ob polnoči) pozove streak check za včerajšnji dan. */
    suspend fun executeMidnightStreakCheck() = repository.runMidnightStreakCheck()
}

package com.example.myapplication.domain.gamification

import com.example.myapplication.domain.model.AchievementProfile
import com.example.myapplication.domain.model.UserDayStatus
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.flow

/**
 * Rezultat zaključenega workout-a.
 * unlockedBadges: seznam badge ID-jev (ne Badge objektov — brez data layer odvisnosti).
 */
data class WorkoutCompletionResult(
    val unlockedBadges: List<String> = emptyList(),
    val xpAwarded: Int,
    val isCritical: Boolean
)

data class GamificationState(
    val weeklyTarget: Int = 0,
    val workoutDoneToday: Boolean = false
)

/**
 * UseCase za gamification logiko.
 *
 * Faza 21: recordWorkoutCompletion() in restDayInitiated() sedaj oba kličeta
 * repository.moveToNextDay() — en SSOT za vse aktivnostne zaključke.
 *
 * Clean Architecture: komunicira SAMO z GamificationRepository (domain interface).
 * KMP-ready: brez Android, data.settings, data.UserProfile odvisnosti.
 */
class ManageGamificationUseCase(
    private val repository: GamificationRepository
) {

    fun getGamificationStateFlow(): Flow<GamificationState> = flow {
        try { emit(repository.getGamificationState()) }
        catch (_: Exception) { emit(GamificationState()) }
    }

    // ─────────────────────────────────────────────────────────────────────────
    // recordWorkoutCompletion — izračuna XP in delegira na moveToNextDay()
    //
    // @param isRestDay      true = extra workout na rest dnevu → REST_WORKOUT_DONE
    // @param incrementPlanDay true = redni workout → plan_day +1
    // ─────────────────────────────────────────────────────────────────────────
    suspend fun recordWorkoutCompletion(
        caloriesBurned: Double,
        hour: Int,
        isRestDay: Boolean = false,
        incrementPlanDay: Boolean = true
    ): WorkoutCompletionResult {

        val calorieXP   = (caloriesBurned / 8).toInt()
        val baseXP      = 50
        val isCritical  = kotlin.random.Random.nextFloat() < 0.1f
        val finalBaseXP = if (isCritical) baseXP * 2 else baseXP
        val totalXP     = finalBaseXP + calorieXP

        val newStatus = if (isRestDay) UserDayStatus.REST_WORKOUT_DONE else UserDayStatus.WORKOUT_DONE
        val xpReason  = if (isRestDay) "REST_WORKOUT_COMPLETE" else "WORKOUT_COMPLETE"

        repository.moveToNextDay(
            newStatus        = newStatus,
            xpToBeAwarded    = totalXP,
            xpReason         = xpReason,
            caloriesBurned   = caloriesBurned,
            incrementPlanDay = incrementPlanDay && !isRestDay
        )

        return WorkoutCompletionResult(emptyList(), totalXP, isCritical)
    }

    suspend fun awardXP(amount: Int, reason: String) = repository.awardXP(amount, reason)

    suspend fun recordPlanCreation() = repository.awardXP(100, "PLAN_CREATED")

    suspend fun recordLoginOnly() = repository.awardXP(10, "DAILY_LOGIN")

    fun getBadgeProgress(badgeId: String, profile: AchievementProfile): Int {
        return when (badgeId) {
            "first_workout", "committed_10", "committed_50",
            "committed_100", "committed_250", "committed_500" ->
                profile.totalWorkoutsCompleted
            "calorie_crusher_1k", "calorie_crusher_5k", "calorie_crusher_10k" ->
                profile.totalCaloriesBurned.toInt()
            "level_5", "level_10", "level_25", "level_50" ->
                profile.level
            "first_follower", "social_butterfly", "influencer", "celebrity" ->
                profile.followers
            "early_bird"  -> profile.earlyBirdWorkouts
            "night_owl"   -> profile.nightOwlWorkouts
            "week_warrior", "month_master", "year_champion" ->
                profile.currentLoginStreak
            "first_plan", "plan_master" ->
                profile.totalPlansCreated
            else -> 0
        }
    }

    suspend fun checkAndSyncBadgesOnStartup(): List<String> = emptyList()

    /**
     * Faza 4b / 21: Uporabnik je opravil raztezanje na rest dnevu.
     *
     * Server-side guard: če je danes že "WORKOUT_DONE" ali "REST_WORKOUT_DONE",
     * akcija ni dovoljena — vrne obstoječi streak brez spremembe.
     *
     * Faza 21: Kliče moveToNextDay(REST_DAY_DONE) namesto starih updateStreak() + awardXP().
     *
     * @return Novi streak po posodobitvi (ali obstoječi če akcija ni dovoljena).
     */
    suspend fun restDayInitiated(): Int {
        val todayStatus = runCatching { repository.getTodayStatus() }
            .getOrDefault(UserDayStatus.WORKOUT_PENDING)

        // Guard: redni trening je danes že opravljen → raztezanje ni dovoljeno
        if (todayStatus == UserDayStatus.WORKOUT_DONE || todayStatus == UserDayStatus.REST_WORKOUT_DONE) {
            return runCatching { repository.getCurrentStreak() }.getOrDefault(0)
        }

        // REST_DAY_DONE = streak+1, plan_day nespremenjen, +10 XP
        val newStreak = repository.moveToNextDay(
            newStatus      = UserDayStatus.REST_DAY_DONE,
            xpToBeAwarded  = 10,
            xpReason       = "REST_DAY",
            caloriesBurned = 0.0,
            incrementPlanDay = false
        )
        return if (newStreak > 0) newStreak else runCatching { repository.getCurrentStreak() }.getOrDefault(0)
    }

    /** Worker (ob polnoči) pozove streak check za včerajšnji dan. */
    suspend fun executeMidnightStreakCheck() = repository.runMidnightStreakCheck()
}

package com.example.myapplication.domain.model

/**
 * Čisti domenski model za streak stanje.
 * Brez Android in Firestore odvisnosti — primeren za KMP.
 *
 * todayStatus vrednosti: "WORKOUT_DONE" | "STRETCHING_DONE" | "FROZEN" | "MISSED" | null
 */
data class Streak(
    val days: Int = 0,
    val freezes: Int = 0,
    /** Kakšen status je danes vpisan v dailyHistory mapo */
    val todayStatus: String? = null
) {
    /** Streak je aktiven, če je vsaj 1 dan */
    val isActive: Boolean get() = days > 0

    /** Streak Freeze je na voljo */
    val isFreezeAvailable: Boolean get() = freezes > 0

    /** Danes je cilj že opravljen (workout ali stretching) */
    val isTodayCompleted: Boolean
        get() = todayStatus == "WORKOUT_DONE" || todayStatus == "STRETCHING_DONE"

    /** Danes je bil porabljen freeze */
    val isTodayFrozen: Boolean get() = todayStatus == "FROZEN"

    /** Danes je bil zamrznjen streak (reset) */
    val isTodayMissed: Boolean get() = todayStatus == "MISSED"
}

package com.example.myapplication.domain.model

/**
 * Čisti domenski model za streak stanje.
 * Brez Android in Firestore odvisnosti — primeren za KMP.
 *
 * todayStatus je zdaj tipsko-varni [UserDayStatus] namesto String.
 */
data class Streak(
    val days: Int = 0,
    val freezes: Int = 0,
    /** Tipsko-varni status današnjega dne */
    val todayStatus: UserDayStatus = UserDayStatus.WORKOUT_PENDING
) {
    /** Streak je aktiven, če je vsaj 1 dan */
    val isActive: Boolean get() = days > 0

    /** Streak Freeze je na voljo */
    val isFreezeAvailable: Boolean get() = freezes > 0

    /** Danes je cilj že opravljen (workout ali stretching) */
    val isTodayCompleted: Boolean get() = todayStatus.isDoneToday

    /** Danes je bil porabljen freeze */
    val isTodayFrozen: Boolean get() = todayStatus == UserDayStatus.FROZEN

    /** Danes je bil zamrznjen streak (reset) */
    val isTodayMissed: Boolean get() = todayStatus == UserDayStatus.MISSED
}

package com.example.myapplication.domain.model

/**
 * SSOT za stanje trenutnega dne v planu.
 *
 * Nadomešča raztresene String konstante ("WORKOUT_DONE", "STRETCHING_DONE", ...)
 * po vsej kodi z enim tipsko-varnim enum razredom.
 *
 * Firestore shrani vrednost [firestoreValue] — npr. "WORKOUT_DONE".
 * Branje: [UserDayStatus.fromFirestore(rawString)].
 *
 * KMP-ready: brez Android odvisnosti.
 */
enum class UserDayStatus(val firestoreValue: String) {

    /** Workout dan — trening še ni opravljen. Privzeto za delovne dni. */
    WORKOUT_PENDING(""),

    /** Trening uspešno opravljen. Streak +1, plan_day +1 (redni workout). */
    WORKOUT_DONE("WORKOUT_DONE"),

    /** Rest dan — raztezanje še čaka. Privzeto za počitniške dni. */
    REST_DAY_PENDING("PENDING_STRETCHING"),

    /** Raztezanje na rest dnevu opravljeno. Streak +1, plan_day ostane. */
    REST_DAY_DONE("STRETCHING_DONE"),

    /** Dodatni trening na rest dnevu. Streak ohranjen (ne poveča), plan_day ostane. */
    REST_WORKOUT_DONE("REST_WORKOUT_DONE"),

    /** Streak Freeze je bil porabljen za ta dan. Streak ohranjen. */
    FROZEN("FROZEN"),

    /** Dan zamešan brez aktivnosti, freeze ni bil na voljo. Streak = 0. */
    MISSED("MISSED");

    // ── Pomožne lastnosti ────────────────────────────────────────────────────

    /**
     * Vrne [true] kadar dan šteje kot "zaključen" — ni potrebna nadaljnja akcija.
     * Pokriva: redni workout, raztezanje, dodatni rest-day workout.
     */
    val isDoneToday: Boolean
        get() = this == WORKOUT_DONE || this == REST_DAY_DONE || this == REST_WORKOUT_DONE

    /**
     * Vrne [true] kadar ta status prispeva k streak +1.
     * REST_WORKOUT_DONE ohrani streak (ne poveča).
     */
    val contributesToStreak: Boolean
        get() = this == WORKOUT_DONE || this == REST_DAY_DONE

    /**
     * Vrne [true] kadar plan_day mora napredovati za +1.
     * Samo redni workout (ne extra, ne stretching).
     */
    val shouldIncrementPlanDay: Boolean
        get() = this == WORKOUT_DONE

    // ── Companion ────────────────────────────────────────────────────────────

    companion object {
        /**
         * Pretvori surovi Firestore string v tipsko-varni [UserDayStatus].
         *
         * @param value Raw string iz Firestore dailyHistory (ali null če ni vnosa).
         * @param isRestDay Če [true] in [value] je null/prazen → vrne [REST_DAY_PENDING]
         *                  namesto [WORKOUT_PENDING].
         */
        fun fromFirestore(value: String?, isRestDay: Boolean = false): UserDayStatus =
            when (value) {
                "WORKOUT_DONE"       -> WORKOUT_DONE
                "STRETCHING_DONE"    -> REST_DAY_DONE
                "PENDING_STRETCHING" -> REST_DAY_PENDING
                "REST_WORKOUT_DONE"  -> REST_WORKOUT_DONE
                "FROZEN"             -> FROZEN
                "MISSED"             -> MISSED
                else                 -> if (isRestDay) REST_DAY_PENDING else WORKOUT_PENDING
            }
    }
}

