/** * Repository interface za branje workout statistik. * * Nadomešča direktno klicanje UserProfileManager in UserPreferencesRepository * iz domain layer-a (Clean Architecture: UseCase komunicira samo z interfejsi). * * KMP-ready: brez Android odvisnosti. * Implementacija živi v data/workout/UserWorkoutStatsRepository.kt. */ interface WorkoutStatsRepository { /** * Vrni workout statistike za danega uporabnika. * @param email Email za Firestore iskanje * @return WorkoutStats ali null, če podatki niso na voljo */ suspend fun getWorkoutStats(email: String): WorkoutStats?
